input.commands:
# clean file and simplify list to avoid loop limit
printf 'Buy groceries\nWrite tests\nDeploy app\n' > /app/tasks.txt

# Rewrite todo.sh with a simpler list (no while loop) to stay under command limit
cat > /app/todo.sh << 'EOF'
#!/usr/bin/env bash
TASKS_FILE="/app/tasks.txt"
touch "$TASKS_FILE"

cmd_add() {
    local task="$*"
    [[ -z "$task" ]] && { echo "Error: provide a task." >&2; exit 1; }
    echo "$task" >> "$TASKS_FILE"
    local n; n=$(wc -l < "$TASKS_FILE")
    echo "Added task #${n}: \"${task}\""
}

cmd_list() {
    [[ ! -s "$TASKS_FILE" ]] && { echo "No tasks found."; return; }
    echo "--- TODO LIST ---"
    cat -n "$TASKS_FILE"
    echo "-----------------"
    local c; c=$(wc -l < "$TASKS_FILE")
    echo "${c} task(s) total"
}

cmd_done() {
    local num="$1"
    [[ -z "$num" || ! "$num" =~ ^[0-9]+$ ]] && { echo "Error: invalid number." >&2; exit 1; }
    local total; total=$(wc -l < "$TASKS_FILE")
    [[ "$num" -gt "$total" ]] && { echo "Error: task #${num} not found (only ${total} tasks)." >&2; exit 1; }
    local task; task=$(sed -n "${num}p" "$TASKS_FILE")
    sed -i.bak "${num}d" "$TASKS_FILE" && rm -f "${TASKS_FILE}.bak"
    echo "Removed task #${num}: \"${task}\""
}

case "$1" in
    add)  shift; cmd_add "$@" ;;
    list) cmd_list ;;
    done) cmd_done "$2" ;;
    *)    echo "Usage: todo.sh add <task> | list | done <number>"; exit 1 ;;
esac
EOF
chmod +x /app/todo.sh
echo "Script ready."

