input.commands:
awk '
  /^#/ { headings[NR] = $0 }
  { lines[NR] = $0; total = NR }
  END {
    # Build TOC lines (skip the very first heading — it is the title)
    toc = ""
    first = 1
    for (i = 1; i <= total; i++) {
      if (headings[i] != "") {
        if (first) { first = 0; continue }   # skip title line
        # Strip leading #-signs and the space after them
        text = headings[i]
        gsub(/^#+[[:space:]]+/, "", text)
        # Build anchor: lowercase + spaces→hyphens
        anchor = tolower(text)
        gsub(/ /, "-", anchor)
        toc = toc "- [" text "](#" anchor ")\n"
      }
    }

    # Print file, inserting TOC after the first heading line
    inserted = 0
    for (i = 1; i <= total; i++) {
      print lines[i]
      if (!inserted && headings[i] != "") {
        # After the first heading, print blank line + TOC
        print ""
        printf "%s", toc
        inserted = 1
      }
    }
  }
' /doc/README.md > /tmp/README_new.md

# Verify the result looks correct before overwriting
cat /tmp/README_new.md

awk '
BEGIN { total=0; inserted=0 }
{
