input.commands:
awk -F'=' '
# Pass 1: load v1 keys/values
NR==FNR {
    keys_v1[$1] = $2
    next
}
# Pass 2: process v2 keys/values
{
    key = $1
    val = $2
    keys_v2[key] = val

    if (key in keys_v1) {
        if (keys_v1[key] != val)
            changed[key] = keys_v1[key] " -> " val
    } else {
        added[key] = val
    }
}
END {
    # Find removed keys (in v1 but not in v2)
    for (k in keys_v1)
        if (!(k in keys_v2))
            removed[k] = keys_v1[k]

    print "============================================"
    print "  Configuration Diff: v1.conf vs v2.conf"
    print "============================================"

    print ""
    print "ADDED KEYS (" length(added) ")"
    print "--------------------------------------------"
    if (length(added) == 0)
        print "  (none)"
    for (k in added)
        printf "  + %-20s = %s\n", k, added[k]

    print ""
    print "REMOVED KEYS (" length(removed) ")"
    print "--------------------------------------------"
    if (length(removed) == 0)
        print "  (none)"
    for (k in removed)
        printf "  - %-20s = %s\n", k, removed[k]

    print ""
    print "CHANGED VALUES (" length(changed) ")"
    print "--------------------------------------------"
    if (length(changed) == 0)
        print "  (none)"
    for (k in changed)
        printf "  ~ %-20s   %s\n", k, changed[k]

    print ""
    print "UNCHANGED KEYS"
    print "--------------------------------------------"
    n = 0
    for (k in keys_v1)
        if ((k in keys_v2) && !(k in changed)) {
            printf "  = %-20s = %s\n", k, keys_v1[k]
            n++
        }
    if (n == 0) print "  (none)"

    print "============================================"
}
' /data/v1.conf /data/v2.conf

awk -F'=' '
NR==FNR {
    v1_val[$1] = $2
    next
}
{
    v2_val[$1] = $2
}
END {
    for (k in v1_val) {
        if (k in v2_val) {
            if (v1_val[k] != v2_val[k])
                changed[k] = v1_val[k] SUBSEP v2_val[k]
            else
                unchanged[k] = v1_val[k]
        } else {
            removed[k] = v1_val[k]
        }
    }
    for (k in v2_val) {
        if (!(k in v1_val))
            added[k] = v2_val[k]
    }

    na = 0; for (k in added)   na++
    nr = 0; for (k in removed) nr++
    nc = 0; for (k in changed) nc++
    nu = 0; for (k in unchanged) nu++

    print "============================================"
    print "  Configuration Diff: v1.conf vs v2.conf"
    print "============================================"

    print ""
    print "ADDED KEYS (" na ")"
    print "--------------------------------------------"
    if (na == 0) print "  (none)"
    for (k in added)   printf "  + %-20s = %s\n", k, added[k]

    print ""
    print "REMOVED KEYS (" nr ")"
    print "--------------------------------------------"
    if (nr == 0) print "  (none)"
    for (k in removed) printf "  - %-20s = %s\n", k, removed[k]

    print ""
    print "CHANGED VALUES (" nc ")"
    print "--------------------------------------------"
    if (nc == 0) print "  (none)"
    for (k in changed) {
        split(changed[k], parts, SUBSEP)
        printf "  ~ %-20s   %s -> %s\n", k, parts[1], parts[2]
    }

    print ""
    print "UNCHANGED KEYS (" nu ")"
    print "--------------------------------------------"
    if (nu == 0) print "  (none)"
    for (k in unchanged) printf "  = %-20s = %s\n", k, unchanged[k]

    print "============================================"
}
' /data/v1.conf /data/v2.conf

