    default  = substr(rhs, start, length(rhs)-start)   # strip trailing "}"

    # Choose value: override beats default
    if (key in overrides) {
      value = overrides[key]
      source = "(override)"
    } else {
      value = default
      source = "(default)"
    }

    printf "%s=%s   %s\n", key, value, source
    print key "=" value >> outfile
    next
  }
' overrides=/config/overrides.txt outfile=/app/.env \
  /config/overrides.txt /config/template.env

mkdir -p /app && \
awk '
  NR == FNR {
    if ($0 ~ /=/ && $0 !~ /^#/) {
      eq = index($0, "=")
      k  = substr($0, 1, eq-1)
      v  = substr($0, eq+1)
      overrides[k] = v
    }
    next
  }
  $0 ~ /=/ {
    eq      = index($0, "=")
    key     = substr($0, 1, eq-1)
    rhs     = substr($0, eq+1)
    # rhs looks like ${KEY:-default}  -- extract between :- and last }
    s       = index(rhs, ":-")
    default = substr(rhs, s+2, length(rhs)-s-2)

    if (key in overrides) {
      value  = overrides[key]
      source = "(override)"
    } else {
      value  = default
      source = "(default)"
    }

    printf "%-12s = %-30s %s\n", key, value, source > "/dev/stderr"
    print key "=" value
  }
' /config/overrides.txt /config/template.env | tee /app/.env >/dev/null && \
echo "" && echo "=== /app/.env written successfully ===" && echo "" && cat /app/.env

