# --- Step 1: Parse deps.txt and topologically sort targets ---

# Build adjacency / dependency data using only bash built-ins + standard tools
DEP_FILE=/project/deps.txt

# Extract all targets (left-hand side of ':')
targets=$(awk -F: '{print $1}' "$DEP_FILE" | tr -d ' ')

# Topological sort (Kahn's algorithm) in pure bash+awk
topo=$(awk '
BEGIN { n = 0 }
{
    # split "target: dep1 dep2 ..."
    split($0, parts, /:[[:space:]]*/);
    tgt = parts[1];
    gsub(/[[:space:]]/, "", tgt);
    nodes[tgt] = 1;
    n++;
    if (parts[2] == "") {
        indegree[tgt] += 0   # ensure key exists
    } else {
        split(parts[2], deps, /[[:space:]]+/);
        for (d in deps) {
            dep = deps[d];
            if (dep == "") continue;
            # edge: dep -> tgt  (dep must come before tgt)
            adj[dep] = adj[dep] " " tgt;
            indegree[tgt]++;
        }
    }
}
END {
    # seed queue with nodes that have no dependencies
    q = ""; qlen = 0;
    for (nd in nodes) {
        if (!(nd in indegree) || indegree[nd] == 0) {
            queue[qlen++] = nd;
        }
    }
    # process queue
    head = 0;
    while (head < qlen) {
        cur = queue[head++];
        order = order " " cur;
        n_adj = split(adj[cur], nexts, " ");
        for (i = 1; i <= n_adj; i++) {
            nxt = nexts[i];
            if (nxt == "") continue;
            indegree[nxt]--;
            if (indegree[nxt] == 0) {
                queue[qlen++] = nxt;
            }
        }
    }
    print order;
}
' "$DEP_FILE")

echo "Resolved build order:$topo"

# --- Step 2: Generate build.sh ---
mkdir -p /project/out

BUILDSH=/project/build.sh
cat > "$BUILDSH" <<'HEADER'
#!/usr/bin/env bash
# Auto-generated build script — do not edit by hand
set -euo pipefail

mkdir -p /project/out

build_target() {
    local target="$1"
    echo "[BUILD] $target"
    echo "built: $target" > "/project/out/$target"
}

HEADER

# Emit one build_target call per target, in sorted order
for t in $topo; do
    echo "build_target $t" >> "$BUILDSH"
done

cat >> "$BUILDSH" <<'FOOTER'

echo ""
echo "All targets built successfully."
FOOTER

chmod +x "$BUILDSH"

echo ""
echo "=== Generated build.sh ==="
cat "$BUILDSH"

# The awk topo sort ran but its output went to a subshell + got interpolated oddly.
# Let's do the whole thing cleanly: write the topo-sort to a temp file, then read it back.

DEP_FILE=/project/deps.txt

# Run topo sort, capture clean output to a file
awk '
BEGIN { n = 0 }
{
    split($0, parts, /:[[:space:]]*/);
    tgt = parts[1];
    gsub(/[[:space:]]/, "", tgt);
    if (tgt == "") next;
    nodes[tgt] = 1;
    if (parts[2] != "") {
        split(parts[2], deps, /[[:space:]]+/);
        for (d in deps) {
            dep = deps[d];
            if (dep == "") continue;
            adj[dep] = adj[dep] " " tgt;
            indegree[tgt]++;
        }
    }
}
END {
    qlen = 0;
    for (nd in nodes) {
        if (!(nd in indegree) || indegree[nd]+0 == 0) {
            queue[qlen++] = nd;
        }
    }
    head = 0;
    while (head < qlen) {
        cur = queue[head++];
        print cur;
        n_adj = split(adj[cur], nexts, " ");
        for (i = 1; i <= n_adj; i++) {
            nxt = nexts[i];
            if (nxt == "") continue;
            indegree[nxt]--;
            if (indegree[nxt]+0 == 0) {
                queue[qlen++] = nxt;
            }
        }
    }
}
' "$DEP_FILE" > /tmp/build_order.txt

echo "=== Topological order ==="
cat /tmp/build_order.txt

# The file looks fine — spaces are real spaces. The awk split on /:[[:space:]]*/
# is not splitting correctly because "app: lib utils" has only ONE colon but split on
# /:[[:space:]]*/ should work. Let's debug the awk parsing directly.

awk '{
    n = split($0, parts, /:[[:space:]]*/);
    print "LINE=[" $0 "] n=" n;
    for (i=1;i<=n;i++) print "  parts[" i "]=[" parts[i] "]";
}' /project/deps.txt

# awk split() with a regex separator isn't working as a literal split the same way here —
# it's treating the whole string as one part. Let's use FS=":" instead, then handle fields.

awk -F: '{
    n = split($0, parts, ":");
    print "n=" n;
    for(i=1;i<=n;i++) print "  [" parts[i] "]";
}' /project/deps.txt

# Perfect — using ":" as a literal string separator works correctly.
# Now build the full solution cleanly.

DEP_FILE=/project/deps.txt

awk -F: '
{
    tgt = $1;
    gsub(/[[:space:]]/, "", tgt);
    if (tgt == "") next;
    nodes[tgt] = 1;

    deps_str = $2;
